import { validateName, validateEmail, validatePhone } from '../src/validators.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

// Test 1: validateName works correctly
assert(validateName('  Alice  ') === 'Alice', 'validateName should trim whitespace');
try { validateName(''); assert(false, 'Should throw for empty name'); } catch (e) {
  assert(e.message.includes('name') && e.message.includes('empty'), 'Error format: ' + e.message);
}
try { validateName(null); assert(false, 'Should throw for null name'); } catch (e) {
  assert(e.message.includes('name') && e.message.includes('required'), 'Error format: ' + e.message);
}

// Test 2: validateEmail works correctly
assert(validateEmail('  bob@test.com  ') === 'bob@test.com', 'validateEmail should trim whitespace');
try { validateEmail('no-at-sign'); assert(false, 'Should throw for invalid email'); } catch (e) {
  assert(e.message.includes('email') && e.message.includes('@'), 'Error format: ' + e.message);
}
try { validateEmail(''); assert(false, 'Should throw for empty email'); } catch (e) {
  assert(e.message.includes('email') && e.message.includes('empty'), 'Error format: ' + e.message);
}

// Test 3: validatePhone works correctly
assert(validatePhone('  +1 (555) 123-4567  ') === '+1 (555) 123-4567', 'validatePhone should trim whitespace');
try { validatePhone('abc'); assert(false, 'Should throw for invalid phone'); } catch (e) {
  assert(e.message.includes('phone'), 'Error format: ' + e.message);
}
try { validatePhone(null); assert(false, 'Should throw for null phone'); } catch (e) {
  assert(e.message.includes('phone') && e.message.includes('required'), 'Error format: ' + e.message);
}

// Test 4: all validators share consistent error format for required fields
const fields = [
  ['name', validateName],
  ['email', validateEmail],
  ['phone', validatePhone]
];
for (const [field, fn] of fields) {
  try { fn(null); } catch (e) {
    assert(e.message === field + ' is required', 'Required error for ' + field + ' should be "' + field + ' is required" but got "' + e.message + '"');
  }
  try { fn('   '); } catch (e) {
    assert(e.message === field + ' must not be empty', 'Empty error for ' + field + ' should be "' + field + ' must not be empty" but got "' + e.message + '"');
  }
}

// Test 5: source code uses assertNonEmpty helper (no duplicated null/empty/length checks)
import { readFileSync } from 'node:fs';
const source = readFileSync(new URL('../src/validators.mjs', import.meta.url), 'utf-8');
assert(source.includes('assertNonEmpty'), 'Source should contain an assertNonEmpty helper function');
const nullCheckCount = (source.match(/=== null/g) || []).length;
assert(nullCheckCount <= 1, 'Should have at most 1 null check (in assertNonEmpty), found ' + nullCheckCount);

console.log('ALL TESTS PASSED');
